def sortList(head):
    if not head or not head.next:
        return head

    def get_mid(node):
        slow, fast = node, node.next
        while fast and fast.next:
            slow = slow.next
            fast = fast.next.next
        mid = slow.next
        slow.next = None
        return mid

    def merge(l1, l2):
        dummy = type(l1)(0)
        cur = dummy
        while l1 and l2:
            if l1.val <= l2.val:
                cur.next = l1
                l1 = l1.next
            else:
                cur.next = l2
                l2 = l2.next
            cur = cur.next
        cur.next = l1 or l2
        return dummy.next

    mid = get_mid(head)
    left = sortList(head)
    right = sortList(mid)
    return merge(left, right)

